funding_dict = {}
for record in funding_data:
    proj_name = record.get('Project_Name', '')
    funding_dict[proj_name] = {
        'Funding_Source': record.get('Funding_Source', ''),
        'Amount': int(record.get('Amount', 0))
    }

# Function to extract project status from text
status_map = {}

for doc in civic_docs:
    text = doc.get('text', '')

    # Look for project patterns
    # Projects often appear with their names followed by updates/schedule
    lines = text.split('\n')

    current_project = None

    for i, line in enumerate(lines):
        line = line.strip()

        # Skip empty lines
        if not line:
            continue

        # Look for potential project names (capitalize, often not bullet points)
        # Skip known headers
        skip_patterns = ['Capital Improvement Projects', 'Disaster Recovery Projects', 
                        'RECOMMENDED ACTION', 'DISCUSSION:', 'Page ', 'Agenda Item',
                        'To:', 'Prepared by:', 'Approved by:', 'Date prepared:', 'Meeting date:',
                        'Subject:', 'cid:', 'Public Works Commission', 'Staff has also prepared']

        should_skip = any(skip in line for skip in skip_patterns)
        if should_skip:
            continue

        # Project names often appear before "Updates:" or "Project Schedule:"
        if 'Updates:' in line or 'Project Schedule:' in line:
            # The previous non-empty line might be the project name
            if current_project:
                # Check for status indicators in following lines
                status_indicators = []
                for j in range(i, min(i+10, len(lines))):
                    next_line = lines[j].strip()
                    if 'Construction was completed' in next_line or 'Notice of completion' in next_line:
                        status_map[current_project] = 'completed'
                        break
                    elif 'Complete Design:' in next_line or 'Final Design:' in next_line:
                        status_map[current_project] = 'design'
                        break
                    elif 'Begin Construction:' in next_line:
                        status_map[current_project] = 'design'
                        break
                    elif 'construction' in next_line.lower() and 'under construction' in next_line.lower():
                        status_map[current_project] = 'design'  # In progress
                        break

        # Check if this line could be a project name (not a bullet, decent length, title case)
        if len(line) > 10 and not line.startswith('(') and not line.startswith('•') and not line.startswith('-'):
            # Check if it looks like a project name (contains project-like words or is title-like)
            project_indicators = ['Project', 'Improvements', 'Repairs', 'Replacement', 'Drainage', 
                                'Road', 'Street', 'Bridge', 'Culvert', 'Park', 'System', 'Facility']
            if any(indicator in line for indicator in project_indicators):
                # Might be a project name, store it
                current_project = line

# Now combine funding data with status information
results = []
for proj_name, funding_info in funding_dict.items():
    # Find status for this project or similar project
    status = 'not started'  # default

    # Direct match
    if proj_name in status_map:
        status = status_map[proj_name]
    else:
        # Try to find partial matches (base project name without suffix)
        base_name = proj_name.split('(')[0].strip()
        for known_project, known_status in status_map.items():
            if base_name in known_project or known_project in base_name:
                status = known_status
                break

    results.append({
        'Project_Name': proj_name,
        'Funding_Source': funding_info['Funding_Source'],
        'Amount': funding_info['Amount'],
        'Status': status
    })

